contracts/FarcasterOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title FarcasterOracle
 * @notice Oracle for Farcaster social data metrics
 * @dev Validators submit social metrics from Neynar API
 */
contract FarcasterOracle is Ownable, ReentrancyGuard {
    struct SocialMetrics {
        uint256 mentions24h;        // Number of mentions in last 24 hours
        int256 sentimentScore;      // Sentiment score: -10000 to +10000 (basis points)
        uint256 engagementRate;     // Engagement rate in basis points (e.g., 1550 = 15.5%)
        uint256 uniqueUsers;        // Number of unique users mentioning
        uint256 totalEngagement;    // Total likes + recasts + replies
        uint256 topCastFid;         // FID of the top performing cast
        uint256 timestamp;
    }

    struct Submission {
        address validator;
        SocialMetrics metrics;
        uint256 timestamp;
        bool processed;
    }

    // Oracle configuration
    string public name;
    string public symbol;
    string public targetToken;          // Token symbol being tracked (e.g., "DEGEN")
    address public registry;
    uint8 public consensusThreshold;    // Percentage (51-100)
    uint256 public updateFrequency;     // Seconds between updates
    uint256 public lastUpdate;

    // Validator management
    address[5] public validators;
    mapping(address => bool) public isValidator;
    mapping(address => uint256) public validatorSubmissionCount;

    // Current consensus data
    SocialMetrics public latestMetrics;
    Submission[] public currentSubmissions;
    mapping(address => bool) public hasSubmittedThisRound;

    // Events
    event MetricsSubmitted(
        address indexed validator,
        uint256 mentions24h,
        int256 sentimentScore,
        uint256 timestamp
    );
    event ConsensusReached(
        uint256 mentions24h,
        int256 sentimentScore,
        uint256 engagementRate,
        uint256 timestamp
    );
    event ValidatorsUpdated(address[5] validators);

    constructor(
        string memory _name,
        string memory _symbol,
        string memory _targetToken,
        uint8 _consensusThreshold,
        uint256 _updateFrequency,
        address _registry,
        address[5] memory _validators
    ) Ownable(msg.sender) {
        require(_consensusThreshold >= 51 && _consensusThreshold <= 100, "Invalid threshold");
        require(bytes(_targetToken).length > 0, "Target token required");

        name = _name;
        symbol = _symbol;
        targetToken = _targetToken;
        consensusThreshold = _consensusThreshold;
        updateFrequency = _updateFrequency;
        registry = _registry;

        // Set validators
        for (uint256 i = 0; i < 5; i++) {
            require(_validators[i] != address(0), "Invalid validator");
            validators[i] = _validators[i];
            isValidator[_validators[i]] = true;
        }

        emit ValidatorsUpdated(_validators);
    }

    /**
     * @notice Submit social metrics data
     * @dev Only validators can submit
     */
    function submitMetrics(
        uint256 _mentions24h,
        int256 _sentimentScore,
        uint256 _engagementRate,
        uint256 _uniqueUsers,
        uint256 _totalEngagement,
        uint256 _topCastFid
    ) external nonReentrant {
        require(isValidator[msg.sender], "Not a validator");
        require(!hasSubmittedThisRound[msg.sender], "Already submitted");
        require(_sentimentScore >= -10000 && _sentimentScore <= 10000, "Invalid sentiment");
        require(_engagementRate <= 10000, "Invalid engagement rate");

        unchecked {
            // Create submission
            SocialMetrics memory metrics = SocialMetrics({
                mentions24h: _mentions24h,
                sentimentScore: _sentimentScore,
                engagementRate: _engagementRate,
                uniqueUsers: _uniqueUsers,
                totalEngagement: _totalEngagement,
                topCastFid: _topCastFid,
                timestamp: block.timestamp
            });

            currentSubmissions.push(Submission({
                validator: msg.sender,
                metrics: metrics,
                timestamp: block.timestamp,
                processed: false
            }));

            hasSubmittedThisRound[msg.sender] = true;
            validatorSubmissionCount[msg.sender]++;

            emit MetricsSubmitted(msg.sender, _mentions24h, _sentimentScore, block.timestamp);

            // Check if consensus reached
            uint256 requiredSubmissions = (5 * consensusThreshold) / 100;
            if (currentSubmissions.length >= requiredSubmissions) {
                _calculateConsensus();
            }
        }
    }

    /**
     * @notice Calculate consensus from submissions
     * @dev Uses median for numeric values
     */
    function _calculateConsensus() private {
        uint256 count = currentSubmissions.length;
        require(count > 0, "No submissions");

        // Use unchecked for all array operations to prevent overflow panics
        unchecked {
            // Arrays for sorting
            uint256[] memory mentions = new uint256[](count);
            int256[] memory sentiments = new int256[](count);
            uint256[] memory engagements = new uint256[](count);
            uint256[] memory users = new uint256[](count);
            uint256[] memory totalEng = new uint256[](count);

            // Collect values
            for (uint256 i = 0; i < count; i++) {
                mentions[i] = currentSubmissions[i].metrics.mentions24h;
                sentiments[i] = currentSubmissions[i].metrics.sentimentScore;
                engagements[i] = currentSubmissions[i].metrics.engagementRate;
                users[i] = currentSubmissions[i].metrics.uniqueUsers;
                totalEng[i] = currentSubmissions[i].metrics.totalEngagement;
            }

            // Sort and get medians
            _sortUint256(mentions);
            _sortInt256(sentiments);
            _sortUint256(engagements);
            _sortUint256(users);
            _sortUint256(totalEng);

            uint256 mid = count / 2;

            // Update latest metrics with consensus values
            latestMetrics = SocialMetrics({
                mentions24h: mentions[mid],
                sentimentScore: sentiments[mid],
                engagementRate: engagements[mid],
                uniqueUsers: users[mid],
                totalEngagement: totalEng[mid],
                topCastFid: currentSubmissions[0].metrics.topCastFid, // Use first submission's top cast
                timestamp: block.timestamp
            });

            lastUpdate = block.timestamp;

            emit ConsensusReached(
                latestMetrics.mentions24h,
                latestMetrics.sentimentScore,
                latestMetrics.engagementRate,
                block.timestamp
            );
        } // End unchecked block

        // Reset for next round
        _resetSubmissions();
    }

    /**
     * @notice Reset submissions for new round
     */
    function _resetSubmissions() private {
        for (uint256 i = 0; i < currentSubmissions.length; i++) {
            hasSubmittedThisRound[currentSubmissions[i].validator] = false;
        }
        delete currentSubmissions;
    }

    /**
     * @notice Check if oracle needs update
     */
    function needsUpdate() external view returns (bool) {
        return block.timestamp >= lastUpdate + updateFrequency;
    }

    /**
     * @notice Get current submission count
     */
    function getCurrentSubmissionCount() external view returns (uint256) {
        return currentSubmissions.length;
    }

    /**
     * @notice Get specific submission
     */
    function getSubmission(uint256 index) external view returns (
        address validator,
        uint256 mentions24h,
        int256 sentimentScore,
        uint256 engagementRate,
        uint256 timestamp
    ) {
        require(index < currentSubmissions.length, "Invalid index");
        Submission memory sub = currentSubmissions[index];
        return (
            sub.validator,
            sub.metrics.mentions24h,
            sub.metrics.sentimentScore,
            sub.metrics.engagementRate,
            sub.timestamp
        );
    }

    /**
     * @notice Get latest consensus metrics
     */
    function getLatestMetrics() external view returns (
        uint256 mentions24h,
        int256 sentimentScore,
        uint256 engagementRate,
        uint256 uniqueUsers,
        uint256 totalEngagement,
        uint256 topCastFid,
        uint256 timestamp
    ) {
        return (
            latestMetrics.mentions24h,
            latestMetrics.sentimentScore,
            latestMetrics.engagementRate,
            latestMetrics.uniqueUsers,
            latestMetrics.totalEngagement,
            latestMetrics.topCastFid,
            latestMetrics.timestamp
        );
    }

    // Sorting helpers (simple bubble sort for small arrays)
    function _sortUint256(uint256[] memory arr) private pure {
        uint256 n = arr.length;
        if (n <= 1) return; // Prevent underflow when n=0 or n=1

        // Use unchecked to prevent overflow panics, since we know n > 1
        unchecked {
            for (uint256 i = 0; i < n - 1; i++) {
                for (uint256 j = 0; j < n - i - 1; j++) {
                    if (arr[j] > arr[j + 1]) {
                        (arr[j], arr[j + 1]) = (arr[j + 1], arr[j]);
                    }
                }
            }
        }
    }

    function _sortInt256(int256[] memory arr) private pure {
        uint256 n = arr.length;
        if (n <= 1) return; // Prevent underflow when n=0 or n=1

        // Use unchecked to prevent overflow panics, since we know n > 1
        unchecked {
            for (uint256 i = 0; i < n - 1; i++) {
                for (uint256 j = 0; j < n - i - 1; j++) {
                    if (arr[j] > arr[j + 1]) {
                        (arr[j], arr[j + 1]) = (arr[j + 1], arr[j]);
                    }
                }
            }
        }
    }

    /**
     * @notice Update validators (only owner)
     */
    function updateValidators(address[5] memory _validators) external onlyOwner {
        // Clear old validators
        for (uint256 i = 0; i < 5; i++) {
            isValidator[validators[i]] = false;
        }

        // Set new validators
        for (uint256 i = 0; i < 5; i++) {
            require(_validators[i] != address(0), "Invalid validator");
            validators[i] = _validators[i];
            isValidator[_validators[i]] = true;
        }

        emit ValidatorsUpdated(_validators);
    }
}

contracts/OracleFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./PriceOracle.sol";
import "./FarcasterOracle.sol";
import "./OracleRegistry.sol";

/**
 * @title OracleFactory
 * @notice Factory contract for deploying new oracle instances
 * @dev Creates and registers oracles in a single transaction
 */
contract OracleFactory {
    address public registry;
    address[] public validators;

    event OracleDeployed(
        address indexed oracleAddress,
        address indexed creator,
        string name,
        string symbol
    );

    constructor(address _registry) {
        registry = _registry;
    }

    /**
     * @notice Set validator addresses (5 Cloudflare Workers)
     */
    function setValidators(address[] memory _validators) external {
        require(_validators.length <= 5, "Max 5 validators");
        validators = _validators;
    }

    /**
     * @notice Deploy a new price oracle
     */
    function deployPriceOracle(
        string memory _name,
        string memory _symbol,
        uint8 _consensusThreshold,
        uint256 _updateFrequency
    ) external returns (address) {
        require(validators.length > 0, "Validators not set");

        // Deploy new PriceOracle
        PriceOracle oracle = new PriceOracle(
            _name,
            _symbol,
            _consensusThreshold,
            _updateFrequency,
            registry,
            validators
        );

        address oracleAddress = address(oracle);

        // Register in OracleRegistry
        OracleRegistry(registry).registerOracle(
            oracleAddress,
            _name,
            "price",
            _updateFrequency,
            _consensusThreshold
        );

        emit OracleDeployed(oracleAddress, msg.sender, _name, _symbol);

        return oracleAddress;
    }

    /**
     * @notice Deploy a new Farcaster oracle for social metrics
     */
    function deployFarcasterOracle(
        string memory _name,
        string memory _symbol,
        string memory _targetToken,
        uint8 _consensusThreshold,
        uint256 _updateFrequency
    ) external returns (address) {
        require(validators.length == 5, "Must have exactly 5 validators");

        // Convert dynamic array to fixed array[5]
        address[5] memory validatorArray;
        for (uint i = 0; i < 5; i++) {
            validatorArray[i] = validators[i];
        }

        // Deploy new FarcasterOracle
        FarcasterOracle oracle = new FarcasterOracle(
            _name,
            _symbol,
            _targetToken,
            _consensusThreshold,
            _updateFrequency,
            registry,
            validatorArray
        );

        address oracleAddress = address(oracle);

        // Register in OracleRegistry
        OracleRegistry(registry).registerOracle(
            oracleAddress,
            _name,
            "farcaster",
            _updateFrequency,
            _consensusThreshold
        );

        emit OracleDeployed(oracleAddress, msg.sender, _name, _symbol);

        return oracleAddress;
    }

    /**
     * @notice Get current validators
     */
    function getValidators() external view returns (address[] memory) {
        return validators;
    }
}

contracts/OracleRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title OracleRegistry
 * @notice Central registry for all FEEDS oracles
 * @dev Tracks oracle deployments, validators, and manages consensus
 */
contract OracleRegistry is Ownable, ReentrancyGuard {
    struct Oracle {
        address oracleAddress;
        address creator;
        string name;
        string oracleType; // "price", "weather", "custom"
        uint256 updateFrequency; // in seconds
        uint8 consensusThreshold; // percentage (0-100)
        bool isActive;
        uint256 createdAt;
        uint256 lastUpdate;
    }

    struct Validator {
        address validatorAddress;
        string endpoint; // Cloudflare Worker URL
        bool isActive;
        uint256 validationCount;
        uint256 lastValidation;
    }

    // Oracle tracking
    mapping(address => Oracle) public oracles;
    mapping(address => bool) public isRegisteredOracle;
    address[] public allOracles;
    mapping(address => address[]) public userOracles; // user => oracle addresses

    // Validator tracking
    Validator[5] public validators;
    mapping(address => uint256) public validatorIndex; // validator address => index
    uint256 public activeValidatorCount;

    // Events
    event OracleRegistered(
        address indexed oracleAddress,
        address indexed creator,
        string name,
        string oracleType
    );
    event OracleDeactivated(address indexed oracleAddress);
    event ValidatorAdded(address indexed validator, string endpoint, uint256 index);
    event ValidatorRemoved(address indexed validator, uint256 index);
    event DataUpdated(address indexed oracle, uint256 timestamp);

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Register a new oracle
     */
    function registerOracle(
        address _oracleAddress,
        string memory _name,
        string memory _oracleType,
        uint256 _updateFrequency,
        uint8 _consensusThreshold
    ) external nonReentrant {
        require(!isRegisteredOracle[_oracleAddress], "Oracle already registered");
        require(_consensusThreshold >= 51 && _consensusThreshold <= 100, "Invalid threshold");

        Oracle memory newOracle = Oracle({
            oracleAddress: _oracleAddress,
            creator: msg.sender,
            name: _name,
            oracleType: _oracleType,
            updateFrequency: _updateFrequency,
            consensusThreshold: _consensusThreshold,
            isActive: true,
            createdAt: block.timestamp,
            lastUpdate: 0
        });

        oracles[_oracleAddress] = newOracle;
        isRegisteredOracle[_oracleAddress] = true;
        allOracles.push(_oracleAddress);
        userOracles[msg.sender].push(_oracleAddress);

        emit OracleRegistered(_oracleAddress, msg.sender, _name, _oracleType);
    }

    /**
     * @notice Deactivate an oracle (only creator can call)
     */
    function deactivateOracle(address _oracleAddress) external {
        require(isRegisteredOracle[_oracleAddress], "Oracle not registered");
        require(oracles[_oracleAddress].creator == msg.sender, "Not oracle creator");

        oracles[_oracleAddress].isActive = false;
        emit OracleDeactivated(_oracleAddress);
    }

    /**
     * @notice Add a validator (Cloudflare Worker)
     */
    function addValidator(
        uint256 _index,
        address _validatorAddress,
        string memory _endpoint
    ) external onlyOwner {
        require(_index < 5, "Invalid validator index");
        require(!validators[_index].isActive, "Validator slot occupied");

        validators[_index] = Validator({
            validatorAddress: _validatorAddress,
            endpoint: _endpoint,
            isActive: true,
            validationCount: 0,
            lastValidation: 0
        });

        validatorIndex[_validatorAddress] = _index;
        activeValidatorCount++;

        emit ValidatorAdded(_validatorAddress, _endpoint, _index);
    }

    /**
     * @notice Remove a validator
     */
    function removeValidator(uint256 _index) external onlyOwner {
        require(_index < 5, "Invalid validator index");
        require(validators[_index].isActive, "Validator not active");

        address validatorAddr = validators[_index].validatorAddress;

        delete validators[_index];
        delete validatorIndex[validatorAddr];
        activeValidatorCount--;

        emit ValidatorRemoved(validatorAddr, _index);
    }

    /**
     * @notice Record a data update from validators
     */
    function recordUpdate(address _oracleAddress) external {
        require(isRegisteredOracle[_oracleAddress], "Oracle not registered");
        require(validators[validatorIndex[msg.sender]].isActive, "Not active validator");

        oracles[_oracleAddress].lastUpdate = block.timestamp;
        validators[validatorIndex[msg.sender]].validationCount++;
        validators[validatorIndex[msg.sender]].lastValidation = block.timestamp;

        emit DataUpdated(_oracleAddress, block.timestamp);
    }

    /**
     * @notice Get oracle details
     */
    function getOracle(address _oracleAddress) external view returns (Oracle memory) {
        require(isRegisteredOracle[_oracleAddress], "Oracle not registered");
        return oracles[_oracleAddress];
    }

    /**
     * @notice Get all oracles for a user
     */
    function getUserOracles(address _user) external view returns (address[] memory) {
        return userOracles[_user];
    }

    /**
     * @notice Get all registered oracles
     */
    function getAllOracles() external view returns (address[] memory) {
        return allOracles;
    }

    /**
     * @notice Get active validators
     */
    function getActiveValidators() external view returns (Validator[5] memory) {
        return validators;
    }

    /**
     * @notice Get total oracle count
     */
    function getOracleCount() external view returns (uint256) {
        return allOracles.length;
    }
}

contracts/PriceOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title PriceOracle
 * @notice Stores and validates price data with multi-validator consensus
 * @dev Each oracle instance is deployed for a specific price feed
 */
contract PriceOracle is AccessControl, ReentrancyGuard {
    bytes32 public constant VALIDATOR_ROLE = keccak256("VALIDATOR_ROLE");

    struct PriceData {
        uint256 price;
        uint256 timestamp;
        uint8 decimals;
    }

    struct ValidationSubmission {
        uint256 price;
        uint256 timestamp;
        address validator;
    }

    // Oracle configuration
    string public name;
    string public symbol; // e.g., "ETH/USD"
    uint8 public consensusThreshold; // percentage (51-100)
    uint256 public updateFrequency; // minimum seconds between updates
    address public registry;

    // Current price data
    PriceData public latestPrice;

    // Validation tracking
    mapping(uint256 => ValidationSubmission[]) public pendingValidations; // round => submissions
    mapping(uint256 => mapping(address => bool)) public hasSubmitted; // round => validator => submitted
    uint256 public currentRound;
    uint256 public lastUpdateTime;

    // Events
    event PriceSubmitted(address indexed validator, uint256 price, uint256 round);
    event PriceUpdated(uint256 price, uint256 timestamp, uint256 round);
    event ConsensusReached(uint256 round, uint256 finalPrice, uint8 agreementPercentage);
    event ConsensusFailed(uint256 round, string reason);

    constructor(
        string memory _name,
        string memory _symbol,
        uint8 _consensusThreshold,
        uint256 _updateFrequency,
        address _registry,
        address[] memory _validators
    ) {
        require(_consensusThreshold >= 51 && _consensusThreshold <= 100, "Invalid threshold");
        require(_validators.length > 0, "Need validators");

        name = _name;
        symbol = _symbol;
        consensusThreshold = _consensusThreshold;
        updateFrequency = _updateFrequency;
        registry = _registry;
        currentRound = 1;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);

        // Grant validator role to all provided validators
        for (uint256 i = 0; i < _validators.length; i++) {
            _grantRole(VALIDATOR_ROLE, _validators[i]);
        }
    }

    /**
     * @notice Submit price data (only validators)
     */
    function submitPrice(
        uint256 _price,
        uint8 _decimals
    ) external onlyRole(VALIDATOR_ROLE) nonReentrant {
        require(_price > 0, "Invalid price");
        require(!hasSubmitted[currentRound][msg.sender], "Already submitted");

        // Create submission
        ValidationSubmission memory submission = ValidationSubmission({
            price: _price,
            timestamp: block.timestamp,
            validator: msg.sender
        });

        pendingValidations[currentRound].push(submission);
        hasSubmitted[currentRound][msg.sender] = true;

        emit PriceSubmitted(msg.sender, _price, currentRound);

        // Check if we can reach consensus
        _tryReachConsensus(_decimals);
    }

    /**
     * @notice Internal function to attempt consensus
     */
    function _tryReachConsensus(uint8 _decimals) internal {
        ValidationSubmission[] memory submissions = pendingValidations[currentRound];
        uint256 submissionCount = submissions.length;

        // Need at least 2 submissions
        if (submissionCount < 2) {
            return;
        }

        // Calculate median price
        uint256[] memory prices = new uint256[](submissionCount);
        for (uint256 i = 0; i < submissionCount; i++) {
            prices[i] = submissions[i].price;
        }

        // Simple bubble sort for median calculation
        for (uint256 i = 0; i < prices.length; i++) {
            for (uint256 j = i + 1; j < prices.length; j++) {
                if (prices[i] > prices[j]) {
                    uint256 temp = prices[i];
                    prices[i] = prices[j];
                    prices[j] = temp;
                }
            }
        }

        uint256 medianPrice = prices[prices.length / 2];

        // Check agreement percentage
        uint256 agreementCount = 0;
        uint256 tolerance = (medianPrice * 5) / 100; // 5% tolerance

        for (uint256 i = 0; i < prices.length; i++) {
            if (
                prices[i] >= medianPrice - tolerance &&
                prices[i] <= medianPrice + tolerance
            ) {
                agreementCount++;
            }
        }

        uint8 agreementPercentage = uint8((agreementCount * 100) / submissionCount);

        if (agreementPercentage >= consensusThreshold) {
            // Consensus reached!
            latestPrice = PriceData({
                price: medianPrice,
                timestamp: block.timestamp,
                decimals: _decimals
            });

            lastUpdateTime = block.timestamp;

            emit ConsensusReached(currentRound, medianPrice, agreementPercentage);
            emit PriceUpdated(medianPrice, block.timestamp, currentRound);

            // Start new round
            currentRound++;
        } else if (submissionCount >= 5) {
            // All validators submitted but no consensus
            emit ConsensusFailed(currentRound, "Consensus threshold not met");
            currentRound++;
        }
    }

    /**
     * @notice Get latest price
     */
    function getLatestPrice() external view returns (uint256 price, uint256 timestamp, uint8 decimals) {
        require(latestPrice.timestamp > 0, "No price data available");
        return (latestPrice.price, latestPrice.timestamp, latestPrice.decimals);
    }

    /**
     * @notice Check if update is needed
     */
    function needsUpdate() external view returns (bool) {
        return block.timestamp >= lastUpdateTime + updateFrequency;
    }

    /**
     * @notice Get current round submissions
     */
    function getCurrentRoundSubmissions() external view returns (ValidationSubmission[] memory) {
        return pendingValidations[currentRound];
    }

    /**
     * @notice Add a new validator
     */
    function addValidator(address _validator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _grantRole(VALIDATOR_ROLE, _validator);
    }

    /**
     * @notice Remove a validator
     */
    function removeValidator(address _validator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _revokeRole(VALIDATOR_ROLE, _validator);
    }
}

contracts/SubscriptionManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SubscriptionManager
 * @notice Manages FEEDS oracle subscriptions with USDC, ETH, and FEEDS token payments
 */
contract SubscriptionManager is Ownable, ReentrancyGuard {
    IERC20 public immutable usdc;
    IERC20 public feedsToken;
    address public treasury;
    address public priceOracle; // For ETH/USD conversion

    uint256 public constant FEEDS_DISCOUNT = 25; // 25% discount when paying with FEEDS token

    // Subscription tiers
    enum Tier { FREE, STARTER, PRO, ENTERPRISE }

    struct Plan {
        uint256 priceUSDC;        // Price in USDC (6 decimals)
        uint256 callLimit;        // Monthly API call limit
        uint256 updateFrequency;  // Minimum seconds between updates
        bool active;
    }

    struct Subscription {
        Tier tier;
        uint256 expiresAt;
        uint256 monthlyLimit;
        uint256 usedThisMonth;
        uint256 periodStart;
    }

    // Tier => Plan details
    mapping(Tier => Plan) public plans;

    // User => Subscription
    mapping(address => Subscription) public subscriptions;

    // User => Prepaid credits in USD (18 decimals)
    mapping(address => uint256) public credits;

    // User => Monthly overage bill in USD (18 decimals)
    mapping(address => uint256) public monthlyBills;

    // Constants
    uint256 public constant COST_PER_CALL = 5e14; // $0.0005 in 18 decimals
    uint256 public constant USDC_DECIMALS = 6;

    // Events
    event Subscribed(address indexed user, Tier tier, uint256 expiresAt);
    event SubscriptionRenewed(address indexed user, Tier tier, uint256 expiresAt);
    event CreditsAdded(address indexed user, uint256 amount);
    event APICallRecorded(address indexed user, address indexed oracle, uint256 cost);
    event BillPaid(address indexed user, uint256 amount);

    constructor(
        address _usdc,
        address _treasury,
        address _initialOwner
    ) Ownable(_initialOwner) {
        require(_usdc != address(0), "Invalid USDC address");
        require(_treasury != address(0), "Invalid treasury");

        usdc = IERC20(_usdc);
        treasury = _treasury;

        // Initialize plans
        plans[Tier.FREE] = Plan({
            priceUSDC: 0,
            callLimit: 10_000,
            updateFrequency: 300, // 5 minutes
            active: true
        });

        plans[Tier.STARTER] = Plan({
            priceUSDC: 29 * 10**USDC_DECIMALS, // $29
            callLimit: 100_000,
            updateFrequency: 60, // 1 minute
            active: true
        });

        plans[Tier.PRO] = Plan({
            priceUSDC: 99 * 10**USDC_DECIMALS, // $99
            callLimit: 1_000_000,
            updateFrequency: 30, // 30 seconds
            active: true
        });

        plans[Tier.ENTERPRISE] = Plan({
            priceUSDC: 0, // Custom pricing
            callLimit: type(uint256).max,
            updateFrequency: 1, // Custom
            active: true
        });
    }

    /**
     * @notice Subscribe to a tier with USDC
     */
    function subscribeWithUSDC(Tier tier) external nonReentrant {
        require(tier != Tier.ENTERPRISE, "Contact sales for Enterprise");
        Plan memory plan = plans[tier];
        require(plan.active, "Plan not active");

        if (tier != Tier.FREE) {
            require(
                usdc.transferFrom(msg.sender, treasury, plan.priceUSDC),
                "USDC transfer failed"
            );
        }

        _createSubscription(msg.sender, tier, plan);
    }

    /**
     * @notice Subscribe to a tier with ETH (converted at current rate)
     */
    function subscribeWithETH(Tier tier) external payable nonReentrant {
        require(tier != Tier.ENTERPRISE, "Contact sales for Enterprise");
        require(tier != Tier.FREE, "Free tier doesn't require payment");

        Plan memory plan = plans[tier];
        require(plan.active, "Plan not active");

        // Get ETH amount needed
        uint256 ethRequired = getETHPrice(plan.priceUSDC);
        require(msg.value >= ethRequired, "Insufficient ETH");

        // Transfer to treasury
        (bool success, ) = treasury.call{value: msg.value}("");
        require(success, "ETH transfer failed");

        _createSubscription(msg.sender, tier, plan);

        // Refund excess
        if (msg.value > ethRequired) {
            (bool refundSuccess, ) = msg.sender.call{value: msg.value - ethRequired}("");
            require(refundSuccess, "Refund failed");
        }
    }

    /**
     * @notice Subscribe to a tier with FEEDS token (25% discount)
     */
    function subscribeWithFEEDS(Tier tier) external nonReentrant {
        require(tier != Tier.ENTERPRISE, "Contact sales for Enterprise");
        require(tier != Tier.FREE, "Free tier doesn't require payment");
        require(address(feedsToken) != address(0), "FEEDS token not set");

        Plan memory plan = plans[tier];
        require(plan.active, "Plan not active");

        // Calculate discounted price (25% off)
        uint256 discountedPrice = (plan.priceUSDC * (100 - FEEDS_DISCOUNT)) / 100;

        // Get FEEDS amount needed (convert USDC 6 decimals to FEEDS 18 decimals)
        uint256 feedsRequired = getFeedsPrice(discountedPrice);

        require(
            feedsToken.transferFrom(msg.sender, treasury, feedsRequired),
            "FEEDS transfer failed"
        );

        _createSubscription(msg.sender, tier, plan);
    }

    /**
     * @notice Add prepaid credits
     */
    function addCredits(uint256 amountUSDC) external nonReentrant {
        require(amountUSDC > 0, "Amount must be > 0");

        require(
            usdc.transferFrom(msg.sender, treasury, amountUSDC),
            "USDC transfer failed"
        );

        // Convert USDC (6 decimals) to 18 decimals for internal accounting
        uint256 creditsAmount = amountUSDC * 10**(18 - USDC_DECIMALS);
        credits[msg.sender] += creditsAmount;

        emit CreditsAdded(msg.sender, creditsAmount);
    }

    /**
     * @notice Record API call usage (called by OracleRegistry)
     */
    function recordAPICall(address user, address oracle) external {
        require(msg.sender == owner(), "Only owner can record calls");

        Subscription storage sub = subscriptions[user];

        // Reset counter if new period
        if (block.timestamp >= sub.periodStart + 30 days) {
            sub.usedThisMonth = 0;
            sub.periodStart = block.timestamp;
            monthlyBills[user] = 0;
        }

        sub.usedThisMonth++;

        // Charge for overage
        if (sub.usedThisMonth > sub.monthlyLimit) {
            uint256 cost = COST_PER_CALL;

            // Try to deduct from credits first
            if (credits[user] >= cost) {
                credits[user] -= cost;
            } else {
                // Add to monthly bill
                monthlyBills[user] += cost;
            }

            emit APICallRecorded(user, oracle, cost);
        }
    }

    /**
     * @notice Pay monthly bill with USDC
     */
    function payBill() external nonReentrant {
        uint256 bill = monthlyBills[msg.sender];
        require(bill > 0, "No outstanding bill");

        // Convert to USDC (6 decimals)
        uint256 amountUSDC = bill / 10**(18 - USDC_DECIMALS);
        require(amountUSDC > 0, "Bill too small");

        require(
            usdc.transferFrom(msg.sender, treasury, amountUSDC),
            "Payment failed"
        );

        monthlyBills[msg.sender] = 0;

        emit BillPaid(msg.sender, bill);
    }

    /**
     * @notice Get ETH price for USDC amount (using oracle)
     */
    function getETHPrice(uint256 usdcAmount) public view returns (uint256) {
        // TODO: Integrate with Chainlink or Pyth for ETH/USD price
        // For now, assume 1 ETH = $3000
        // usdcAmount is in 6 decimals, ETH is 18 decimals
        uint256 ethPrice = 3000 * 10**USDC_DECIMALS; // $3000 in USDC decimals
        return (usdcAmount * 10**18) / ethPrice;
    }

    /**
     * @notice Get FEEDS token amount for USDC amount (using oracle)
     */
    function getFeedsPrice(uint256 usdcAmount) public view returns (uint256) {
        // TODO: Integrate with DEX price feed for FEEDS/USD price
        // For now, assume 1 FEEDS = $0.01
        // usdcAmount is in 6 decimals, FEEDS is 18 decimals (ERC20 standard)
        uint256 feedsPrice = 1 * 10**(USDC_DECIMALS - 2); // $0.01 in USDC decimals
        return (usdcAmount * 10**18) / feedsPrice;
    }

    /**
     * @notice Get user's subscription details
     */
    function getSubscription(address user) external view returns (
        Tier tier,
        uint256 expiresAt,
        uint256 monthlyLimit,
        uint256 usedThisMonth,
        uint256 remainingCalls,
        uint256 creditBalance,
        uint256 outstandingBill
    ) {
        Subscription memory sub = subscriptions[user];
        tier = sub.tier;
        expiresAt = sub.expiresAt;
        monthlyLimit = sub.monthlyLimit;
        usedThisMonth = sub.usedThisMonth;
        remainingCalls = usedThisMonth >= monthlyLimit ? 0 : monthlyLimit - usedThisMonth;
        creditBalance = credits[user];
        outstandingBill = monthlyBills[user];
    }

    /**
     * @notice Check if user can make API call
     */
    function canMakeCall(address user) external view returns (bool) {
        Subscription memory sub = subscriptions[user];

        // Check subscription is active
        if (block.timestamp > sub.expiresAt) {
            return false;
        }

        // Check if within limit OR has credits/can be billed
        if (sub.usedThisMonth < sub.monthlyLimit) {
            return true;
        }

        // Can still call if they have credits or can be billed
        return credits[user] >= COST_PER_CALL || sub.tier != Tier.FREE;
    }

    /**
     * @notice Update plan details (owner only)
     */
    function updatePlan(
        Tier tier,
        uint256 priceUSDC,
        uint256 callLimit,
        uint256 updateFrequency,
        bool active
    ) external onlyOwner {
        plans[tier] = Plan(priceUSDC, callLimit, updateFrequency, active);
    }

    /**
     * @notice Update treasury address (owner only)
     */
    function updateTreasury(address newTreasury) external onlyOwner {
        require(newTreasury != address(0), "Invalid address");
        treasury = newTreasury;
    }

    /**
     * @notice Set FEEDS token address (owner only)
     */
    function setFeedsToken(address _feedsToken) external onlyOwner {
        require(_feedsToken != address(0), "Invalid address");
        feedsToken = IERC20(_feedsToken);
    }

    /**
     * @notice Grant enterprise subscription (owner only)
     */
    function grantEnterpriseSubscription(
        address user,
        uint256 callLimit,
        uint256 updateFrequency,
        uint256 durationDays
    ) external onlyOwner {
        Plan memory plan = Plan({
            priceUSDC: 0,
            callLimit: callLimit,
            updateFrequency: updateFrequency,
            active: true
        });

        subscriptions[user] = Subscription({
            tier: Tier.ENTERPRISE,
            expiresAt: block.timestamp + (durationDays * 1 days),
            monthlyLimit: callLimit,
            usedThisMonth: 0,
            periodStart: block.timestamp
        });

        emit Subscribed(user, Tier.ENTERPRISE, block.timestamp + (durationDays * 1 days));
    }

    /**
     * @dev Internal function to create subscription
     */
    function _createSubscription(address user, Tier tier, Plan memory plan) private {
        uint256 expiresAt = block.timestamp + 30 days;

        subscriptions[user] = Subscription({
            tier: tier,
            expiresAt: expiresAt,
            monthlyLimit: plan.callLimit,
            usedThisMonth: 0,
            periodStart: block.timestamp
        });

        emit Subscribed(user, tier, expiresAt);
    }
}

